<template>
  <div class="login">
    <!-- 登录方式切换 -->
    <img class="bg" src="../assets/bg.jpg" alt="">
    <div class="applog">
    <van-tabs v-show="!showReg">
      <!-- 账号登录 -->
      <van-tab title="账号登录">
        <van-form @submit="onLogin">
          <van-field
            v-model="account"
            name="account"
            left-icon="phone-o"
            placeholder="请填写手机号码"
            :rules="[
              { required: true },
              { pattern: /^1[3456789]\d{9}$/, message: '手机号码格式错误' },
            ]"
          />
          <van-field
            v-model="password"
            type="password"
            name="password"
            left-icon="lock"
            placeholder="请输入密码"
            :rules="[
              { required: true },
              { pattern: /^\w{5,18}$/, message: '密码由5-18位数字或字母组成' },
            ]"
          />
          <div style="margin: 16px">
            <van-button color="linear-gradient(to right, #f55d45, #fe8b3c)" round block type="info" native-type="submit"
              >登录</van-button
            >
          </div>
          <p class="regist" @click="showReg=true">快速注册</p>
        </van-form>
      </van-tab>

      <!-- 快速登录 -->
      <van-tab title="快速登录">
        <van-form @submit="onSms">
          <van-field
            v-model="tel"
            name="tel"
            left-icon="phone-o"
            placeholder="请填写手机号码"
            :rules="[
              { required: true },
              { pattern: /^1[3456789]\d{9}$/, message: '手机号码格式错误' },
            ]"
          />
          <van-field
            v-model="sms"
            center
            clearable
            left-icon="other-pay"
            placeholder="请输入验证码"
          >
            <template #button>
              <van-button style="font-size:12px;"  @click="getSms" :disabled="countDown<60" round size="small" native-type="button" type="warning">{{countDown >= 60 ? "发送验证码":countDown+'秒'}}</van-button>
            </template>
          </van-field>

          <div style="margin: 16px">
            <van-button color="linear-gradient(to right, #f55d45, #fe8b3c)" round block type="info" native-type="submit"
              >快速登录</van-button
            >
          </div>
           <p class="regist" @click="showReg=true">快速注册</p>
        </van-form>
      </van-tab>
    </van-tabs>  
            <van-form @submit="onRegist" v-if="showReg">
                <p class="registPage">注册账号</p>
                <van-field
                    left-icon="phone-o"
                    v-model="zctel"
                    name="zctel"
                    label=" "
                    label-width="5px"
                    placeholder="输入手机号码"
                    :rules="[{ required: true },
                      { pattern:/^1[3456789]\d{9}$/,message:'手机号码格式错误'}]"
                />
                <van-field
                    left-icon="other-pay"
                    v-model="zcsms"
                    name="zcsms"
                    center
                    clearable
                    label=" "
                    label-width="5px"
                    placeholder="请输入短信验证码"
                    >
                <template #button>
                   <van-button style="font-size:12px;" @click.stop.prevent="registSms" :disabled="countDown<60" round size="small" native-type="button" type="warning">{{countDown >= 60 ? "发送验证码":countDown+'秒'}}</van-button>
                </template>
                </van-field>
                <van-field
                    left-icon="lock"
                    v-model="zcpassword"
                    type="password"
                    name="zcpassword"
                    label=" "
                    label-width="5px"
                    placeholder="请填写登录密码"
                    :rules="[
                    { required: true},
                    { pattern: /^\w{5,18}$/, message: '密码由5-18位数字或字母组成' },

                    ]"
                />
                <div style="margin: 16px;">
                    <van-button round block type="info" native-type="submit" color="linear-gradient(to right, #f55d45, #fe8b3c)">提交</van-button>
                </div>
                <div class="regist">已有账号?<span @click.stop.prevent="showReg=!showReg">立即登录</span></div>
            </van-form>
    </div>
  </div>
</template>

<script>
import { mapMutations, mapActions } from "vuex";
export default {
  data() {
    return {
      account: "",
      password: "",
      tel: "",
      sms:"",
      smsKey:"",
      countDown:60,
      showReg:false,
      zctel:'',
      zcsms:'',
      zcpassword:''
    };
  },
  created(){
   this.axios.get("api/verify_code").then(d=>{
     this.smsKey = d.data.data.key;
     console.log("smsKey=>",this.smsKey);
   })
  },
  methods: {
    // 获取验证码
    getSms(){
    this.axios.post("api/register/verify",{
      key: this.smsKey,
      phone: this.tel,
      type: "login"
    }).then(d=>{
      let da = d.data;
      // 验证码发送成功
      if(da.status == 200){
     let smsTimer = setInterval(()=>{
         this.countDown--;
         if(this.countDown<=0){
           clearInterval(smsTimer);
           this.countDown = 60;
         }
        },1000)
        this.$toast(da.msg);
      }else{
        this.$toast(da.msg)
      }
console.log("短信验证=>",d.data);
    })
    },
    // 验证码登录
    onSms(){
    this.axios.post("api/login/mobile",{
      captcha: this.sms,
      phone: this.tel,
      spread: null
    }).then(data=>{
      // 登录成功时
      if(data.data.status == 200){
        let token = data.data.data.token;
        this.saveToken(token);
        this.getLoginInfo();
        this.$toast({
           message: "登录成功",
            icon: "passed",
            onClose: () => {
              this.$router.push('/');
            },
        })
      }else{
      this.$toast({
        message:data.data.msg,
            icon: "fail",
      })
      }

    })
    },
    // 账号登录
    onLogin(val) {
      this.axios.post("api/login", val).then((data) => {
        console.log(data);

        if (data.data.status == 200) {
          //  在提示之前保存token以及获取用户信息
          this.saveToken(data.data.data.token);
          this.getLoginInfo(data.data.data.token);

          // 登录成功提示
          this.$toast({
            message: "登录成功",
            icon: "passed",
            onClose: () => {
              this.$router.push('/');
            },
          });
        } else {
          this.$toast.fail(data.data.msg);
        }
      });
      console.log(val);
    },
    // 注册验证码
   registSms(){
    this.axios.post("api/register/verify",{
      key: this.smsKey,
      phone: this.zctel,
      type: "register"
    }).then(d=>{
      let da = d.data;
      // 验证码发送成功
      if(da.status == 200){
     let smsTimer = setInterval(()=>{
         this.countDown--;
         if(this.countDown<=0){
           clearInterval(smsTimer);
           this.countDown = 60;
         }
        },1000)
        this.$toast(da.msg);
      }else{
        this.$toast(da.msg)
      }
console.log("短信验证=>",d.data);
    })
    },
    // 注册
     onRegist(value){
        console.log(value)
        this.$axios.post('/api/register',{
            account:value.zctel,
            captcha:value.zcsms,
            password:value.zcpassword,
            spread:null
        }).then(d=>{
            console.log(d)
            if(d.data.status==200){
                //注册成功
                this.$toast({ 
                        message:d.data.msg,
                        icon:"passed",
                        onClose:()=>{
                    this.showReg=false;
                        }
                    })
            }else{
                //注册失败
                this.$toast(d.data.msg)
            }
        })
    },
    ...mapMutations(["saveToken"]),
    ...mapActions(["getLoginInfo"]),
  },
};
</script>
<style lang="less" >
.login{
overflow: hidden;
  .bg{
    width: 100vw;
    height:100vh;
    position: absolute;
    z-index: -3;
  }
  .applog{
    width: 80vw;
    padding: 10px 0;
    height: 280px;
    border: 1px solid salmon;
    margin: 80px auto;
    border-radius:15px;
    box-sizing: border-box;
    background-color: #fff;
    position: relative;
    .regist{
    color: salmon;
    font-size: 12px;
    position: absolute;
    right: 10px;
   
  }
   .registPage{
      font-size: 16px;
      margin: 0 ;
      text-align: center;
    }
  .van-tabs__line{
    background-color: salmon;
  }
  }
  
}
</style>